#include <bits/stdc++.h>
using namespace std;
const int N=55;
int dp[N][N][N][N],a[N][N],n,m;
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++) cin>>a[i][j];
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			for(int i1=1;i1<=n;i1++)
			{
				for(int j1=1;j1<=m;j1++)
				{
					if((i+j+i1+j1!=2*n+2*m)&&(i1==i&&j1==j)) continue;
					int t1=dp[i][j-1][i1][j1-1],t2=dp[i][j-1][i1-1][j1],t3=dp[i-1][j][i1][j1-1],t4=dp[i-1][j][i1-1][j1];
					dp[i][j][i1][j1]=max(max(t1,t2),max(t3,t4));
					dp[i][j][i1][j1]+=(a[i][j]+a[i1][j1]);
				}
			}
		}
	}
	cout<<dp[n][m][n][m];
	return 0;
}
